import{_ as e,o as a,c as s,a2 as l}from"./chunks/framework.D36jym0Z.js";const g=JSON.parse('{"title":"Data and Permissions","description":"","frontmatter":{},"headers":[],"relativePath":"platform-concepts/data-and-permissions.md","filePath":"platform-concepts/data-and-permissions.md","lastUpdated":1784542960000}'),i={name:"platform-concepts/data-and-permissions.md"};function n(o,t,r,d,h,c){return a(),s("div",null,[...t[0]||(t[0]=[l(`<h1 id="data-and-permissions" tabindex="-1">Data and Permissions <a class="header-anchor" href="#data-and-permissions" aria-label="Permalink to &quot;Data and Permissions&quot;">​</a></h1><p>LightMem2 runs entirely on your machine. Understanding what data is stored, where, and what leaves your machine is important.</p><h2 id="what-data-is-stored-locally" tabindex="-1">What Data Is Stored Locally <a class="header-anchor" href="#what-data-is-stored-locally" aria-label="Permalink to &quot;What Data Is Stored Locally&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Data</th><th style="text-align:left;">Location</th><th style="text-align:left;">Purpose</th></tr></thead><tbody><tr><td style="text-align:left;">Configuration files</td><td style="text-align:left;"><code>~/.openclaw/</code>, <code>~/.codex/</code>, <code>~/.claude/</code></td><td style="text-align:left;">Plugin and host settings</td></tr><tr><td style="text-align:left;">Session metrics</td><td style="text-align:left;">In-memory (current session only)</td><td style="text-align:left;">Token counts, cache stats, cost</td></tr><tr><td style="text-align:left;">Backup files</td><td style="text-align:left;"><code>*.tokenpilot.bak</code> alongside originals</td><td style="text-align:left;">Recovery on uninstall</td></tr><tr><td style="text-align:left;">CLI state</td><td style="text-align:left;"><code>~/.lightmem2/</code> (if created)</td><td style="text-align:left;">Default host, pinned session</td></tr></tbody></table><h2 id="what-is-not-stored" tabindex="-1">What Is NOT Stored <a class="header-anchor" href="#what-is-not-stored" aria-label="Permalink to &quot;What Is NOT Stored&quot;">​</a></h2><ul><li><strong>Message content</strong>. LightMem2 processes messages in flight but does not persist them.</li><li><strong>API keys</strong>. Never read, stored, or forwarded.</li><li><strong>Personal paths or server addresses</strong>. Only config file paths explicitly set via env vars are used.</li></ul><h2 id="what-leaves-your-machine" tabindex="-1">What Leaves Your Machine <a class="header-anchor" href="#what-leaves-your-machine" aria-label="Permalink to &quot;What Leaves Your Machine&quot;">​</a></h2><p><strong>Nothing by default.</strong> LightMem2&#39;s core runtime and plugins run locally. No telemetry, no analytics, no cloud service.</p><p>The only network traffic is what your agent host already sends to the model API (e.g., Anthropic, OpenAI). LightMem2 may modify the context sent in those requests (that&#39;s its job), but it does not add new external calls.</p><h2 id="plugin-data-access" tabindex="-1">Plugin Data Access <a class="header-anchor" href="#plugin-data-access" aria-label="Permalink to &quot;Plugin Data Access&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Under development</p><p>The formal permission model for plugins is being defined. The current model is based on what TokenPilot needs.</p></div><p>Each plugin declares its data access requirements. TokenPilot needs to:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Access</th><th style="text-align:left;">Why</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Read</strong> message history</td><td style="text-align:left;">To compute cache efficiency and apply reduction</td></tr><tr><td style="text-align:left;"><strong>Read</strong> tool outputs</td><td style="text-align:left;">To trim oversized results</td></tr><tr><td style="text-align:left;"><strong>Read</strong> session metadata</td><td style="text-align:left;">To track session lifecycle</td></tr><tr><td style="text-align:left;"><strong>Write</strong> modified context</td><td style="text-align:left;">To apply stable-prefix rewriting</td></tr><tr><td style="text-align:left;"><strong>Write</strong> config state</td><td style="text-align:left;">To persist mode changes</td></tr></tbody></table><p>Future plugins will declare similar access requirements in their manifest, and the runtime will enforce them.</p><h2 id="cleaning-up" tabindex="-1">Cleaning Up <a class="header-anchor" href="#cleaning-up" aria-label="Permalink to &quot;Cleaning Up&quot;">​</a></h2><p>To remove all LightMem2 data:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Remove configuration files</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.codex/tokenpilot.json</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.claude/tokenpilot.json</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Remove CLI state</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -rf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.lightmem2/</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Restore backups (or just remove .tokenpilot.bak files)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">find</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;*.tokenpilot.bak&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -delete</span></span></code></pre></div><p>Follow the <a href="/LightMem2/user-guide/uninstall-and-rollback">Uninstall and Rollback</a> guide for a complete cleanup.</p><h2 id="privacy-summary" tabindex="-1">Privacy Summary <a class="header-anchor" href="#privacy-summary" aria-label="Permalink to &quot;Privacy Summary&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Concern</th><th style="text-align:left;">Answer</th></tr></thead><tbody><tr><td style="text-align:left;">Does LightMem2 send data externally?</td><td style="text-align:left;">No</td></tr><tr><td style="text-align:left;">Does LightMem2 store conversations?</td><td style="text-align:left;">No</td></tr><tr><td style="text-align:left;">Does LightMem2 read API keys?</td><td style="text-align:left;">No</td></tr><tr><td style="text-align:left;">Can I verify this?</td><td style="text-align:left;">Yes — all code is open source</td></tr><tr><td style="text-align:left;">Where are config files?</td><td style="text-align:left;"><code>~/.openclaw/</code>, <code>~/.codex/</code>, <code>~/.claude/</code></td></tr></tbody></table><h2 id="next" tabindex="-1">Next <a class="header-anchor" href="#next" aria-label="Permalink to &quot;Next&quot;">​</a></h2><ul><li><a href="/LightMem2/user-guide/uninstall-and-rollback">Uninstall and Rollback</a> — complete cleanup guide</li><li><a href="/LightMem2/project/security">Security</a> — security policy</li></ul>`,22)])])}const y=e(i,[["render",n]]);export{g as __pageData,y as default};
